import{_ as e,H as t,f as s,i}from"./chunks/framework.DbTCwA-u.js";const c=JSON.parse('{"title":"Player Designs","description":"Configure custom MiniMessage and Vault designs in players.yml.","frontmatter":{"title":"Player Designs","description":"Configure custom MiniMessage and Vault designs in players.yml."},"headers":[],"relativePath":"config/players.md","filePath":"config/players.md"}'),n={name:"config/players.md"};function l(r,a,o,d,h,p){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="player-designs-players-yml" tabindex="-1">Player Designs (players.yml) <a class="header-anchor" href="#player-designs-players-yml" aria-label="Permalink to &quot;Player Designs (players.yml)&quot;">​</a></h1><p>This is where the visual magic happens. The <code>players.yml</code> file allows you to define <strong>unlimited groups</strong> using the modern <em>MiniMessage</em> engine, interpolated with the versatility of <em>PlaceholderAPI</em>.</p><hr><h2 id="🎨-understanding-minimessage" tabindex="-1">🎨 Understanding MiniMessage <a class="header-anchor" href="#🎨-understanding-minimessage" aria-label="Permalink to &quot;🎨 Understanding MiniMessage&quot;">​</a></h2><p>Instead of using old and limited color codes like <code>&amp;c</code> or <code>&amp;l</code>, you can now use highly descriptive HTML tags.</p><table tabindex="0"><thead><tr><th>Tag</th><th>Result</th></tr></thead><tbody><tr><td><code>&lt;red&gt;</code></td><td>Pure red text</td></tr><tr><td><code>&lt;#ff00ff&gt;</code></td><td>Text using custom HEX code</td></tr><tr><td><code>&lt;bold&gt;</code></td><td><strong>Bold</strong> text</td></tr><tr><td><code>&lt;gradient:red:blue&gt;</code></td><td>Generates a smooth transition between two or more colors</td></tr></tbody></table><hr><h2 id="👥-default-format" tabindex="-1">👥 Default Format <a class="header-anchor" href="#👥-default-format" aria-label="Permalink to &quot;👥 Default Format&quot;">​</a></h2><p>Any user who does not fit into a rank hierarchy will fall into this design:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">players</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;yellow&gt;Player&lt;/yellow&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;PLAYER&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><p><em>You will notice that you can create as many lines as you want simply by adding hyphens (<code>-</code>) to the list.</em></p><hr><h2 id="👑-advanced-ranks-vault" tabindex="-1">👑 Advanced Ranks &amp; Vault <a class="header-anchor" href="#👑-advanced-ranks-vault" aria-label="Permalink to &quot;👑 Advanced Ranks &amp; Vault&quot;">​</a></h2><p>You can create nametag groups that exactly match your rank name in <strong>LuckPerms</strong> (or any other Vault-compatible permission system). The plugin reads the player&#39;s <em>Primary Group</em> and looks for its equivalent here.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  groups</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    vip</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gradient:gold:yellow&gt;⭐ VIP User&lt;/gradient&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;PLAYER&gt;&lt;/white&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    admin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;red&gt;:rank_dev: Supreme Admin&lt;/red&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gradient:red:dark_red&gt;&lt;bold&gt;&lt;PLAYER&gt;&lt;/bold&gt;&lt;/gradient&gt;&quot;</span></span></code></pre></div><h3 id="🖼️-integration-with-itemsadder-oraxen" tabindex="-1">🖼️ Integration with ItemsAdder / Oraxen <a class="header-anchor" href="#🖼️-integration-with-itemsadder-oraxen" aria-label="Permalink to &quot;🖼️ Integration with ItemsAdder / Oraxen&quot;">​</a></h3><p>If you look closely at the <code>admin</code> format, you&#39;ll notice the text <code>:rank_dev:</code>.</p><p>If you have <strong>ItemsAdder</strong> or any Resource Pack installed on your server, the player&#39;s client will read this and automatically replace the colons with an <strong>actual font image</strong> rendered above the admin&#39;s head.</p><div class="tip custom-block"><p class="custom-block-title">💡 DESIGN TIP</p><p>Avoid making Nametags more than 3 lines long for regular players. Excessive lines can obstruct vision in PvP or dense builds.</p></div>`,19)])])}const k=e(n,[["render",l]]);export{c as __pageData,k as default};
